from fastapi import FastAPI
from pydantic import BaseModel

app = FastAPI(title="Railway Lab App")

class Item(BaseModel):
    name: str
    description: str | None = None

# Phase 1: Basic endpoint
@app.get("/")
def read_root():
    return {"message": "Hello World! This is my Railway deployment for the lab."}

# Phase 2: Added meaningful feature (Data processing / API endpoint)
@app.post("/analyze/")
def analyze_data(item: Item):
    # Simple data processing
    reversed_name = item.name[::-1]
    desc_length = len(item.description) if item.description else 0

    return {
        "status": "success",
        "original_name": item.name,
        "reversed_name": reversed_name,
        "description_length": desc_length,
        "message": "Data processed successfully!"
    }
